import{c as e,Q as a,j as i,m as t}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"十年纪","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/drama-poetry/03-十年纪.md","filePath":"research/machiavelli/machiavelli/drama-poetry/03-十年纪.md"}'),r={name:"research/machiavelli/machiavelli/drama-poetry/03-十年纪.md"};function l(o,p,c,d,n,m){return a(),i("div",null,[...p[0]||(p[0]=[t('<h1 id="十年纪" tabindex="-1">十年纪 <a class="header-anchor" href="#十年纪" aria-label="Permalink to &quot;十年纪&quot;">​</a></h1><p>十年纪第二①</p><p>严重的事件、狂乱的行为， 在接下来的十年中所发生的， 当我杜门封笔归于沉默之后， 3</p><p>各王室、帝国、政府的更迭， 在意大利这块土地上相继出现， 那是由于神的意愿而注定如此， 6</p><p>这些我都将吟唱；我的歌声 将会是充满泪水，尽管我几乎 因为痛苦而变得渐渐丧魂失魄。 9</p><p>缪斯啊，如果你曾激励过我， 就请你给我恩典，让我的诗句 配上以下这些事件的宏伟壮大； 12</p><p>并从你的泉眼中汲出那恩典， 有恒久的力量，让我们的歌声</p><p>① Decennale secondo,创作于1514年左右，原计划写1504-1513年间的事，实际只写到1509年。格律为但 丁三行体，译文未能体现韵脚。</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>至少能够令现在活着的人满意。</p><p>整个世界曾经处在忧虑之中， 每个人都在手上把那缰绳勒紧， 让那疲乏的骏马能够暂时休憩，</p><p>当人称阿尔维阿诺的巴托洛梅奥①, 率领着他的大军，离开那王国②时， 对那位大将军③,心里很是不满；</p><p>为了让他好战性格能够施展， 或者是出于另外一个什么原因， 他心里就有了计划要进入比萨。</p><p>而虽说他随身所带人马不多， 可是对于未来所要下的那盘棋， 他却成了先走一步的那个小卒。</p><p>而你们，想要熄灭这一场火， 很快就做好了所需的一切准备； 于是乎他的计谋便没能够得逞；</p><p>当他到了圣文琴佐的塔下，</p><p>①巴托洛梅奥 · 阿尔维阿诺( Bartolomeo d&#39;Alviano,1455-1515),一位著名的意大利雇佣兵将领。 ②那波利王国。 ③大将军指孔萨尔沃。</p><p>Scritti letterari</p><p>由于你们的贾科米诺①英勇无比， 他的手下便人仰马翻溃不成军。</p><p>这样，由于他的德性②和命运③, 便赢得了这般巨大的荣耀和名声， 从来没有一个普通市民⑨能够做到。</p><p>为了他的家乡这一位倾尽全力， 而为了你们的战旗能熠熠生辉， 他用巨大的正义长久地维系着；</p><p>他贪于功名，却淡于金钱， 以这样的德性，他方才勇敢， 故而他远远胜过我所能夸赞。</p><p>如今他被遗忘和诋毁，躺在 他的家里，穷困、衰老，双目 失明，机运对好人是这般不喜!</p><p>然后，如果我的记忆还可靠， 你们就开始对付比萨人，希望 能够让那场失败把它完全压垮；</p><p>① 贾 科 米 诺( Giacomino) 指佛罗伦萨的将领安东尼奥 · 贾科米尼 · 台巴尔杜齐( Antonio Giacomini Tebalducci), 马基雅维利把1505年8月佛罗伦萨的胜利归功于他。 ② 这里的“德性”( virtù) 指“英勇”。 ③这里的“命运”原文是destino, 不同于马基雅维利在别处常用的“机运” ( fortuna)。 ④“普通市民”,原文是privato cittadino。</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>可是因为比萨几乎毫不惧怕， 你们在那里扎营并没有多久， 而这便是那颗悲惨种子的开端。</p><p>如果说你们丧失了金钱和荣誉， 从人民普遍坚持的看法是如此， 但至少你们满足了民众的愿望。</p><p>这时候，阿斯卡尼奥①死去了， 许多大君主曾起来为他去竞争， 希望让他回到他那天然的国度。</p><p>费拉拉公爵埃尔科莱死了， 腓特烈死了，卡斯蒂利亚的 杰出女王伊丽莎白也死了。②</p><p>于是高卢鸡也加入同党， 与斐迪南修和，并且同意 把富瓦的女儿给他做配偶；③</p><p>还把他在那波利的所有， 作为她的嫁妆，而西班牙王</p><p>①枢机主教阿斯卡尼奥 · 斯福尔扎( Ascanio Sforza ), 是米兰公爵加莱亚佐 · 马里亚 · 斯福尔扎 (Galeazzo Maria Sforza)和“摩尔人”洛多维科 ·斯福尔扎的弟弟。意大利战争中，法国人在1500年将他 虏至里昂，获释后于1503年离开法国。亚历山大六世死后，他两度角逐教皇选举，均告失利，1505年5月 28日在罗马去世。 ②费拉拉公爵埃斯特的埃尔科莱( Ercole d&#39;Este)死于1505年6月15日；那波利废王阿拉贡的腓特烈死于 1504年；卡斯蒂利亚女王伊莎贝拉(伊丽莎白)死于1504年11月26日。 ③“富瓦的女儿”( di Fois la figlia): 伊莎贝拉死后，西班牙国王“天主教徒”斐迪南又与法国富瓦的 热尔曼娜( Germaine de Foix)结婚。</p><p>文学著作 Scritti letterari</p><p>则向他许下许多宏大的诺言。</p><p>这时候，那大公①从布列塔尼 出发，他还从那里率领着 来自那日耳曼尼亚的大军，</p><p>因为他一心一意就要夺取 卡斯蒂利亚的王位，那王位 本该归他，而不是他那岳丈。</p><p>而当这一位刚来到了深海， 他的舰队立刻就被狂风冲击， 这样他被他人的力量所左右；</p><p>因为他的船，被狂风拍打， 在英格兰搁了浅，此地可是 萨福克公爵②绝不乐意看到的。</p><p>他带着人马离开了那地方， 亲自抵达了卡斯蒂利亚王国， 这时斐迪南却早已不在此地；</p><p>①大公指“美男子”菲利普(1478-1506),神圣罗马帝国皇帝马克西米利安一世之子，伊莎贝拉与斐迪 南的女儿“疯女”胡安娜的丈夫。伊莎贝拉死后，胡安娜成了卡斯蒂利亚王位的继承人。为反对斐迪南对 卡斯蒂利亚的兼并，卡斯蒂利亚贵族宣布菲利普为国王，1506年4月菲利普和胡安娜率德意志雇佣军开至 西班牙。 ②萨福克公爵(&#39;I duca di Soffolch)当指百年战争时英国将军威廉 ·德 ·拉 ·波尔( William de la Pole, 1396- 1450),他于1448年被封为萨福克公爵( Duke of Suffolk)。后因战事失利被怀疑通敌。1450年被捕 并关押在伦敦塔，后被判处流放五年，但在英吉利海峡他的船被截，遂被处死。据说是他的政敌约克公爵 所为。</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>①尤利乌斯是好斗的教皇，有“战神”之称，他希望在教皇的旗帜下统一整个意大利。</p><p>决定越过大山，并且支持那个 爱戴他并匍匐在地被征服的派别；</p><p>他用尽了手段、强力和机巧， 终于把热那亚的政府，再一次 各派都统一到他自己的旗帜下。</p><p>然后，为了消除尤利乌斯教皇 的一切怀疑，为表明不会袭击他， 便立即带着人马来到了萨沃纳；</p><p>他在那里等待斐迪南的到来， 后者正要赶回卡斯蒂利亚掌权， 他不久之前方才从那里离开；</p><p>因为那个外国正处于骚乱， 菲利普现在已死去；在回途 他与在此等候的法兰西商谈。</p><p>而皇帝①,这时希望越山南下， 并按照他们的那种古老习惯， 能够在罗马让自己得到加冕；</p><p>他在康斯坦茨召开了全体 贵族的大会，会上他历数</p><p>①指马克西米利安一世。</p><p>文学著作 Scritti letterari</p><p>102</p><p>105</p><p>108</p><p>111</p><p>114</p><p>117</p><p>高卢鸡和法兰西贵族的祸害；</p><p>又下令每个人都跨上战马， 并带上自己的侍从以及步卒， 就在圣高卢日①那天，不得有误。</p><p>但法兰西和马可听说了此事， 便将自己的军队合成一体，并且 在特兰托，联军一同封锁了道路。</p><p>那马可对处于守势还不满意； 而是要打到他家里， 一下就从 帝国夺走了戈里齐亚和的里雅斯特。</p><p>于是马克西米利安就想要休战， 因为他看到这么多方来对付他， 他也就同意割走那两块土地；</p><p>之后这两块土地就成了餐肴， 尽管只是小小的一口，带上毒， 就把圣马可的胃口彻底给败坏。</p><p>因为那皇帝，正如我所说的， 受了冒犯，而在法国好国王看来， 他就好像是威尼斯人耍弄的傻瓜。</p><p>① 1507年10月16日(一说是7月1日)。</p><p>120</p><p>123</p><p>126</p><p>129</p><p>132</p><p>135</p><p>138</p><p>Scritti letterari</p><p>就这样，为了挫败马可的计划， 教皇和西班牙双方就携起手来， 又和帝国以及那黄百合①结了盟。 141</p><p>双方之间的种种协议并未停止， 相反，他们在康布雷达成一致，② 每一方都可以追求自己的利益。 144</p><p>在这期间，你们就采取了 大量的措施，因为对比萨， 你们可是始终睁大了双眼， 147</p><p>并且无论如何也不会放手罢休， 除非将它拿到手；斐迪南和路易 为了让你们得到它而把道路切断。 150</p><p>而你们的邻居们③沿他们的足迹 依样前行，对他们纷纷许下大愿， 冲你们则是每天千百次的纷争； 153</p><p>因此，为了让这事情有把握， 就得灌满他们每个人的喉咙，</p><p>① 百合是法国王室的标志。 ②1508年，马克西米利安和路易十二在康布雷( Cambrai)缔结反威尼斯联盟，教皇尤利乌斯二世于次年 正式加入，4月宣布对威尼斯共和国处以绝罚，之后西班牙、英国、匈牙利、萨伏伊、佛罗伦萨等也相继 加入。 ③“ 邻居们”指以前支持比萨的热那亚和卢卡。</p><p>还有那些始终不断张大着的嘴。</p><p>因此，比萨只剩一座孤城， 你们就迅速地将它团团围住， 谁也不能进入，除非插翅能飞：</p><p>你们将它围困了四月之久， 付出了许多的计谋以及辛劳， 以不小的代价，令它忍受饥馑。</p><p>而虽然它是个顽固的敌人， 但是被必然性所限制并征服，① 它就哭泣着回到那古老的枷锁。</p><p>重启战端的欲望在法兰西 仍未熄灭，盟约缔结了之后， 在伦巴第集结了巨大的军队。</p><p>尤利乌斯教皇也匆忙率部 来到罗马涅，把布里奇盖拉 连同那法恩扎，首先来攻打。</p><p>但是在特莱维和其他要塞， 法兰西和马可发生轻度遭遇 之后，传来的信息时好时坏，</p><p>①指比萨因缺乏食物而不得不投降。</p><p>156</p><p>159</p><p>162</p><p>165</p><p>168</p><p>171</p><p>174</p><p>文学著作 Scritti letterari</p><p>① 维 拉( Vailà), 即阿格纳德洛战役( Battaglia di Agnadello),1509 年5月14日，法军在贾拉达达地区 (Ghiaradadda ) 的阿格纳德洛打败威尼斯军队，使威尼斯人“他们在一日之间把八百年来历尽困苦所取得 的一切都丧失了”(《君主论》第12章)。</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>我可不能迅速地向你们讲述， 就如同后来的那些威尼斯人， 在溃败之后，国力迅速地消失。</p><p>伦巴第被那个基督徒的大王① 占去了一半，而剩下的那部分 则仅以罗马人圣座的名义所拥有；</p><p>罗马涅归了伟大的牧羊人， 没什么商量；而阿拉贡人的王， 也赶着把普利亚收为他的领土。</p><p>但因为那些国度那条顿人② 还没有到达，圣马可就立刻 把帕多瓦和特雷维廖又夺回。</p><p>马克西米利安得知这一消息， 便率领了大军，赶将过来， 要抢走此处，且不遗漏其余。</p><p>而尽管他得到了你们以及 法兰西和西班牙的帮助，但是 如同别的事情，此事也未成功：</p><p>① 基督徒的大王( el gran re de&#39;cristiani) 指法国国王路易十二。 ②条顿人( il Tedesco) 指神圣罗马帝国皇帝。</p><p>195</p><p>198</p><p>201</p><p>204</p><p>207</p><p>210</p><p>Scritti letterari</p><p>因为，虽说他曾经踌躇满志 在帕多瓦数日，最终吃尽苦头、 筋疲力尽，只得拔起他的营寨；</p><p>而被同盟抛弃了的他， 就匆忙地回到了日耳曼， 丢了维琴察他损失惨重……①</p><p>①该诗后半部佚失。</p><p>213</p><p>216</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p>',119)])])}const h=e(r,[["render",l]]);export{_ as __pageData,h as default};
